import { useState } from 'react';
import {OptionButton, SubmitButton, QuizThemeContent} from "./Button"
import { useNavigate } from 'react-router-dom';

export default function StartMenu(){
    const [quizName, setquizName] = useState("");
    const navigate = useNavigate(); 
    return (
        <div className='container'>
            <Header quizName={quizName}></Header>
            <main className="main">
                <div className="startMenuText">
                    <h1 className='subtitle'>Welcome to the <p className='title'>Frontend Quiz!</p></h1>
                    <p className='description'>Pick a subject to get started.</p>
                </div>
                <div className="buttonGroup">
                    <OptionButton onQuizName={setquizName}>
                        <QuizThemeContent name="HTML"></QuizThemeContent>
                    </OptionButton>
                    <OptionButton onQuizName={setquizName}>
                        <QuizThemeContent name="CSS"></QuizThemeContent>
                    </OptionButton>
                    <OptionButton onQuizName={setquizName}>
                        <QuizThemeContent name="Javascript"></QuizThemeContent>
                    </OptionButton>
                    <OptionButton onQuizName={setquizName}>
                        <QuizThemeContent name="Accessibility"></QuizThemeContent>
                    </OptionButton>
                </div>
            </main>
        </div>
    )
}

function Header({quizName}){
    return (
        <header className="header">
            <div className="quizName">
                <h1>{quizName}</h1>
            </div>
            <ToggleColorTheme></ToggleColorTheme>
        </header>
    )
}
function ToggleColorTheme(){
    return (
        <label className="switchTheme">
            <input type="checkbox"></input>
            <span className="switch round"></span>
        </label>
    )
}
